            vm_error(vm, "divzero_error", "division by zero");
        }
        var_setreal(dst, x / y);
    } else if (var_isinstance(a)) {
        ins_binop(vm, "/", ins);
    } else {
        binop_error(vm, "/", a, b);
    }
    dispatch();
}
opcase(MOD): {
    bvalue *dst = RA(), *a = RKB(), *b = RKC();
    if (var_isint(a) && var_isint(b)) {
        var_setint(dst, ibinop(%, a, b));
    } else if (var_isnumber(a) && var_isnumber(b)) {
        var_setreal(dst, mathfunc(fmod)(var_toreal(a), var_toreal(b)));
    } else if (var_isinstance(a)) {
        ins_binop(vm, "%", ins);
    } else {
        binop_error(vm, "%", a, b);
    }
    dispatch();
}
opcase(LT): {
    bbool res = be_vm_islt(vm, RKB(), RKC());
    bvalue *dst;
    reg = vm->reg;
    dst = RA();
    var_setbool(dst, res);
    dispatch();
}
opcase(LE): {
    bbool res = be_vm_isle(vm, RKB(), RKC());
    bvalue *dst;
    reg = vm->reg;
    dst = RA();
    var_setbool(dst, res);
    dispatch();
}
opcase(EQ): {
    bbool res = be_vm_iseq(vm, RKB(), RKC());
    bvalue *dst;
    reg = vm->reg;
    dst = RA();
    var_setbool(dst, res);
    dispatch();
}
opcase(NE): {
    bbool res = be_vm_isneq(vm, RKB(), RKC());
    bvalue *dst;
    reg = vm->reg;
    dst = RA();
    var_setbool(dst, res);
    dispatch();
}
opcase(GT): {
    bbool res = be_vm_isgt(vm, RKB(), RKC());
    bvalue *dst;
    reg = vm->reg;
    dst = RA();
    var_setbool(dst, res);
    dispatch();
}
opcase(GE): {
    bbool res = be_vm_isge(vm, RKB(), RKC());
    bvalue *dst;
    reg = vm->reg;
    dst = RA();
    var_setbool(dst, res);
    dispatch();
}
opcase(CONNECT): {
    bvalue *a = RKB(), *b = RKC();
    if (var_isint(a) && var_isint(b)) {
        make_range(vm, *RKB(), *RKC());
    } else if (var_isstr(a)) {
        connect_str(vm, var_tostr(a), b);
    } else if (var_isinstance(a)) {
        object_binop(vm, "..", *RKB(), *RKC());
    } else {
        binop_error(vm, "..", RKB(), RKC());
    }
    reg = vm->reg;
    *RA() = *vm->top; /* copy result to R(A) */
    dispatch();
}
opcase(AND): {
    bitwise_block(&);
    dispatch();
}
opcase(OR): {
    bitwise_block(|);
    dispatch();
}
opcase(XOR): {
    bitwise_block(^);
    dispatch();
}
opcase(SHL): {
    bitwise_block(<<);
    dispatch();
}
opcase(SHR): {
    bitwise_block(>>);
    dispatch();
}
opcase(NEG): {
    bvalue *dst = RA(), *a = RKB();
    if (var_isint(a)) {
        var_setint(dst, -a->v.i);
    } else if (var_isreal(a)) {
        var_setreal(dst, -a->v.r);
    } else if (var_isinstance(a)) {
        ins_unop(vm, "-*", *RKB());
        reg = vm->reg;
        *RA() = *vm->top; /* copy result to dst */
    } else {
        unop_error(vm, "-", a);
    }
    dispatch();
}
opcase(FLIP): {
    bvalue *dst = RA(), *a = RKB();
    if (var_isint(a)) {
        var_setint(dst, ~a->v.i);
    } else if (var_isinstance(a)) {
        ins_unop(vm, "~", *RKB());
        reg = vm->reg;
        *RA() = *vm->top; /* copy result to dst */
    } else {
        unop_error(vm, "~", a);
    }
    dispatch();
}
opcase(JMP): {
    vm->ip += IGET_sBx(ins);
    dispatch();
}
opcase(JMPT): {
    if (be_value2bool(vm, RA())) {
        vm->ip += IGET_sBx(ins);
    }
    dispatch();
}
opcase(JMPF): {
    if (!be_value2bool(vm, RA())) {
        vm->ip += IGET_sBx(ins);
    }
    dispatch();
}
opcase(CLOSURE): {
    bvalue *dst;
    bproto *p = clos->proto->ptab[IGET_Bx(ins)];
    bclosure *cl = be_newclosure(vm, p->nupvals);
    cl->proto = p;
    reg = vm->reg;
    dst = RA();
    var_setclosure(dst, cl);
    be_initupvals(vm, cl);
