opcase(SETSUPER): {
    bvalue *a = RA(), *b = RKB();
    if (var_isclass(a) && var_isclass(b)) {
        bclass *obj = var_toobj(a);
        be_class_setsuper(obj, var_toobj(b));
    } else {
        vm_error(vm, "type_error",
            "value '%s' does not support set super",
            be_vtype2str(b));
    }
    dispatch();
}
opcase(CLOSE): {
    be_upvals_close(vm, RA());
    dispatch();
}
opcase(IMPORT): {
    bvalue *b = RKB();
